import{_ as o,o as t,c as s,a2 as r}from"./chunks/framework.D5wUhsuj.js";const a="/docs/assets/network-policies-page.c0dH0Lag.png",i="/docs/assets/create-egress-profile-dialog.C8bZsuMd.png",n="/docs/assets/egress-profile-no-internet.B19LloQC.png",l="/docs/assets/egress-profile-destination-rules.CDxhyIBL.png",d="/docs/assets/delete-egress-profile-dialog.BTzddERM.png",k=JSON.parse('{"title":"Network Policies","description":"","frontmatter":{},"headers":[],"relativePath":"admin/network_policies.md","filePath":"admin/network_policies.md","lastUpdated":1783546178000}'),c={name:"admin/network_policies.md"};function p(g,e,h,f,m,u){return t(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="network-policies" tabindex="-1">Network Policies <a class="header-anchor" href="#network-policies" aria-label="Permalink to &quot;Network Policies&quot;">​</a></h1><p>Administrators can use <strong>User Management</strong> &gt; <strong>Network Policies</strong> to define reusable egress profiles for workspace outbound access.</p><p>An egress profile is an allowlist of external destinations. Assign a profile to a workspace from <strong>User Management</strong> &gt; <strong>Workspaces</strong> to control which external hosts workloads in that workspace may reach.</p><h2 id="how-egress-profiles-work" tabindex="-1">How Egress Profiles Work <a class="header-anchor" href="#how-egress-profiles-work" aria-label="Permalink to &quot;How Egress Profiles Work&quot;">​</a></h2><p>Each workspace can have at most one assigned egress profile.</p><p>An assigned profile applies to Istio-injected workloads in the workspace. prokube keeps DNS and required internal egress-control traffic allowed so approved hosts can resolve and route through the egress gateway.</p><div class="warning custom-block"><p class="custom-block-title">Istio sidecar required</p><p>Egress profiles restrict only workloads that are part of the Istio mesh and routed through the platform egress controls. Workloads without Istio sidecar injection are not filtered by these profiles and can still use any network path allowed by the cluster and underlying network.</p></div><p><img src="'+a+'" alt="Network Policies page" loading="lazy"></p><p>The UI shows profile assignment state in the <strong>Egress Profile</strong> column on the Workspaces page:</p><ul><li>profile name and first allowed destination when a profile is assigned;</li><li><strong>No internet access</strong> when the assigned profile has no destinations;</li><li><strong>Profile missing</strong> when a workspace still references a deleted or unavailable profile;</li><li><strong>None</strong> when no profile is assigned.</li></ul><h2 id="create-a-profile" tabindex="-1">Create a Profile <a class="header-anchor" href="#create-a-profile" aria-label="Permalink to &quot;Create a Profile&quot;">​</a></h2><p>Open <strong>User Management</strong> &gt; <strong>Network Policies</strong> and click <strong>Create Profile</strong>.</p><p>Set:</p><ul><li><strong>Name</strong>: display name for administrators. New profile IDs are generated from the name and become stable after creation.</li><li><strong>Description</strong>: optional explanation of intended use.</li><li><strong>Allowed Destinations</strong>: DNS host, protocol, and port combinations.</li></ul><p>Leave <strong>Allowed Destinations</strong> empty to create a <strong>No Internet Access</strong> profile. This blocks external egress while preserving DNS and required internal egress-control traffic.</p><p><img src="'+i+'" alt="Create Egress Profile dialog" loading="lazy"></p><p><img src="'+n+'" alt="No internet access egress profile" loading="lazy"></p><h2 id="destination-rules" tabindex="-1">Destination Rules <a class="header-anchor" href="#destination-rules" aria-label="Permalink to &quot;Destination Rules&quot;">​</a></h2><p>Allowed destinations use explicit host, protocol, and port rows.</p><p>Supported protocols:</p><table tabindex="0"><thead><tr><th>Protocol</th><th>Use for</th></tr></thead><tbody><tr><td><code>HTTP</code></td><td>Plain HTTP traffic, commonly port <code>80</code>.</td></tr><tr><td><code>TLS</code></td><td>HTTPS or other TLS traffic, commonly port <code>443</code>.</td></tr><tr><td><code>TCP</code></td><td>Opaque TCP traffic such as databases or custom services.</td></tr></tbody></table><p>Host rules:</p><ul><li>use DNS hostnames only, for example <code>pypi.org</code> or <code>api.example.com</code>;</li><li>do not include URL schemes, paths, query strings, or fragments;</li><li>exact hosts and one leading wildcard label are supported, for example <code>*.example.com</code>;</li><li>wildcard hosts are supported for <code>HTTP</code> and <code>TLS</code>, but not for <code>TCP</code>.</li></ul><p>Port rules:</p><ul><li>ports must be integers from <code>1</code> to <code>65535</code>;</li><li>duplicate host/port/protocol rows are deduplicated;</li><li><code>TCP</code> destinations must use exact hostnames;</li><li>for opaque <code>TCP</code>, one port can target only one host per profile because same-port TCP routes cannot be distinguished by host.</li></ul><p><img src="'+l+'" alt="Egress profile destination rules" loading="lazy"></p><h2 id="assign-a-profile-to-a-workspace" tabindex="-1">Assign a Profile to a Workspace <a class="header-anchor" href="#assign-a-profile-to-a-workspace" aria-label="Permalink to &quot;Assign a Profile to a Workspace&quot;">​</a></h2><p>Open <strong>User Management</strong> &gt; <strong>Workspaces</strong>, open the row actions for the workspace, and choose <strong>Assign Egress Profile</strong>.</p><p>In the dialog:</p><ol><li>Select the egress profile.</li><li>Click <strong>Save Assignment</strong>.</li></ol><p>To remove an assignment, open the same dialog and click <strong>Clear Assignment</strong>.</p><p>Clearing the assignment removes the derived egress-control resources for that workspace. It does not delete the reusable profile.</p><h2 id="edit-and-delete-profiles" tabindex="-1">Edit and Delete Profiles <a class="header-anchor" href="#edit-and-delete-profiles" aria-label="Permalink to &quot;Edit and Delete Profiles&quot;">​</a></h2><p>Use <strong>Edit</strong> on the Network Policies page to change the profile name, description, or destinations. Assigned workspaces are reconciled after the update.</p><p>Profiles cannot be deleted while assigned to workspaces. Clear all workspace assignments first, then delete the profile.</p><p><img src="'+d+'" alt="Delete Egress Profile dialog" loading="lazy"></p><h2 id="operational-notes" tabindex="-1">Operational Notes <a class="header-anchor" href="#operational-notes" aria-label="Permalink to &quot;Operational Notes&quot;">​</a></h2><ul><li>Egress profiles are administrator-managed and stored as platform configuration.</li><li>Assignment creates workspace-scoped egress-control resources for the selected workspace.</li><li>A profile with no allowed destinations intentionally means no external internet access, not an error.</li><li>Egress control depends on sidecar injection and platform egress-gateway configuration. Workloads that are not covered by those controls may not be restricted by the profile.</li><li>If a user reports that allowed access still fails, check the exact host, protocol, port, DNS resolution, sidecar injection, and whether the workload is in the expected workspace.</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./user_management.html">User Management</a></li><li><a href="./../platform/workspaces.html">Workspaces</a></li><li><a href="./../platform/kubernetes.html">Kubernetes Resources</a></li></ul>',40)])])}const P=o(c,[["render",p]]);export{k as __pageData,P as default};
